// Split register array into individual messages with register address as topic
const data = msg.payload.data;
const baseAddr = msg.payload.address || 0;
const messages = [];
for (let i = 0; i < data.length; i++) {
    messages.push({
        topic: 'register/' + (baseAddr + i),
        payload: data[i],
        registerAddress: baseAddr + i,
        unitId: msg.payload.unitId
    });
}
return [messages];

// Report-By-Exception: only forward if value changed beyond deadband
const DEADBAND = 2;
const key = 'rbe_' + msg.topic;
const prev = flow.get(key);
const curr = msg.payload;

if (prev === undefined || Math.abs(curr - prev) > DEADBAND) {
    flow.set(key, curr);
    msg.changed = true;
    msg.previousValue = prev !== undefined ? prev : null;
    msg.delta = prev !== undefined ? curr - prev : null;
    return msg;
}
// No change beyond deadband → suppress
return null;

// Add ISO timestamp for database logging
msg.timestamp = new Date().toISOString();
msg.payload = {
    register: msg.registerAddress,
    value: msg.payload,
    previous: msg.previousValue,
    delta: msg.delta,
    timestamp: msg.timestamp
};
return msg;
